function startMove(direction){sendCommand("move",direction).catch(showCommandError)}function stopMove(){sendCommand("move","stop").catch(showCommandError)}function showCommandError(error){console.error(error);alert(error.message)}function setupMovementButton(id,direction){const button=document.getElementById(id);button.addEventListener("mousedown",()=>startMove(direction));button.addEventListener("mouseup",stopMove);button.addEventListener("mouseleave",stopMove);button.addEventListener("touchstart",event=>{event.preventDefault();startMove(direction)},{passive:false});button.addEventListener("touchend",event=>{event.preventDefault();stopMove()},{passive:false});button.addEventListener("touchcancel",stopMove)}setupMovementButton("forward","forward");setupMovementButton("backward","backward");setupMovementButton("left","left");setupMovementButton("right","right");document.getElementById("stop").onclick=stopMove;function setupHeadButton(id,direction){document.getElementById(id).onclick=()=>sendCommand("head",direction).catch(showCommandError)}setupHeadButton("head-left","left");setupHeadButton("head-right","right");setupHeadButton("head-up","up");setupHeadButton("head-down","down");setupHeadButton("head-center","center");document.getElementById("face-select").onchange=event=>sendCommand("face",event.target.value).catch(showCommandError);document.getElementById("shell-select").onchange=event=>sendCommand("shell",event.target.value).catch(showCommandError);document.getElementById("led-select").onchange=event=>sendCommand("led",event.target.value).catch(showCommandError);document.getElementById("sound-select").onchange=event=>sendCommand("sound",event.target.value).catch(showCommandError);async function sendMessage(){const input=document.getElementById("message");const message=input.value.trim();if(!message)return;try{await sendCommand("shell_text",message);input.value=""}catch(error){showCommandError(error)}}document.getElementById("message").addEventListener("keydown",event=>{if(event.key==="Enter"&&!event.shiftKey){event.preventDefault();sendMessage()}});